    74→///             PcapBlockOwned::NG(_) => {
    75→///                 // can be statistics (ISB), name resolution (NRB), etc.
    76→///                 eprintln!("unsupported block");
    77→///             },
    78→///             PcapBlockOwned::Legacy(_)
    79→///             | PcapBlockOwned::LegacyHeader(_) => unreachable!(),
